var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_ROOT","text":{"KOREA":"흐이익!?","JPN":"ふええっ！？","ENG":"Eeeek!!","TWN":"嗚嗚嗚！？"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_ROOT","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_ROOT","text":{"KOREA":"하아…… 하…… 바, 바람 소리였구나. 깜짝이야.","JPN":"はあ……は……か、風の音だったんだね。ビックリした。","ENG":"Phew... I-it was just the wind. *Sigh*","TWN":"呼……呼……原來是風聲，嚇我一跳。"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_ROOT","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_ROOT","text":{"KOREA":"으으, 이럴 줄 알았어. 얌전히 시그마를 따라갈 걸 왜 허세나 부려 가지고…….","JPN":"うう、こうなるとは思ってたんだ。強がってないで、大人しくシグマについていけばよかった……","ENG":"Ngh... I knew this would happen. I should've just followed Sigma. Why did I have to act all tough back there...","TWN":"嗚，早知如此就乖乖跟著西格瑪就好，幹嘛打腫臉充胖子……"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_ROOT","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"여기 계셨군요. 헤이븐 님.","JPN":"ここにいたんですね。ヘイブン様。","ENG":"So this is where you’ve been, Mr. Haven.","TWN":"天堂先生，原來您在這。"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_ROOT","face":"UNIT_HATE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_ROOT","text":{"KOREA":"으아아아아! 요괴 마녀다!!","JPN":"うわああああ！　妖怪魔女だ！！","ENG":"AAAAH!! It's a witch monster!!","TWN":"啊啊啊啊！是老巫婆！！"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_ROOT","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"누구더러 요괴 마녀라는 거야!?","JPN":"誰が妖怪魔女よ！？","ENG":"Who are you calling a witch monster?!","TWN":"你叫誰老巫婆！？"},"stage":{"bg":"HALL","slots":{"L":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"HAVEN_HAVEN_NULL_ROOT","face":"UNIT_DESPAIR"}}}},{"id":"L11_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_ROOT","text":{"KOREA":"헤, 헤론이야? 네가 여긴 어떻게……?","JPN":"へ、ヘロン？　どうやってここに……？","ENG":"H-Heron? I-is that you? But h-how did you know I...?","TWN":"海…海倫？你怎麼會在這……？"},"stage":{"bg":"HALL","slots":{"L":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"HAVEN_HAVEN_NULL_ROOT","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"가면도 없이 용케 돌아다니셨군요. 그러다 공포증이라도 도지면 어쩌시려구요.","JPN":"よくも仮面なしで歩き回れましたね。恐怖症が酷くなったらどうするんです？","ENG":"I'm surprised you’ve been running around like this without your mask. What if your phobia kicks in, hmm?","TWN":"沒戴面具還到處亂跑，萬一恐懼症復發的話怎麼辦？"},"stage":{"bg":"HALL","slots":{"L":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HAVEN_HAVEN_NULL_ROOT","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"손님들에게 헤이븐 님의 볼품없는 꼬락서니를 들켰을까 봐 어찌나 조마조마하던지.","JPN":"お客様にヘイブン様のみっともない姿がバレてないか、どれだけハラハラしたことか。","ENG":"I have been so on edge, wondering what will happen if our guests found out that Haven was a scared little kid.","TWN":"而且我也很擔心，萬一您這副模樣被人看到可就不好啦。"},"stage":{"bg":"HALL","slots":{"L":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HAVEN_HAVEN_NULL_ROOT","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"……여긴 왜 왔어.","JPN":"……なんで来たんだよ。","ENG":"...Why are you here?","TWN":"……你來這做什麼？"},"stage":{"bg":"HALL","slots":{"L":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L15_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"당연히 헤이븐 님을 모시러 왔죠.","JPN":"もちろんヘイブン様をお迎えに来たんです。","ENG":"To escort you, of course.","TWN":"當然是來帶您回去的。"},"stage":{"bg":"HALL","slots":{"L":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L16_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"헤이븐 랜드의 주인이 자리를 오래 비우면 아랫사람들이 불안해하니까요.","JPN":"ヘイブンランドの主が長く留守をしてると、下の者たちが不安に思いますからね。","ENG":"If the owner of Havenland is away for too long, his employees will become anxious.","TWN":"天堂樂園的主人若是離開位置太久，底下的人會不安的。"},"stage":{"bg":"HALL","slots":{"L":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L17_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"언제 갈지는……. 내가 정해.","JPN":"いつ帰るかは……僕が決める。","ENG":"I decide... when I go back.","TWN":"什麼時候要回去……由我決定。"},"stage":{"bg":"HALL","slots":{"L":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L19_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"돌아가서 기다리고 있어. 묻고 싶은 얘기가 많으니까.","JPN":"帰って待っててよ。聞きたいことがたくさんあるから。","ENG":"Go back to your office and wait for me there. There are a lot of questions you need to answer.","TWN":"你先回去等著，我有很多事要問你。"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"아뇨. 오히려 제가 묻고 싶네요.","JPN":"いいえ。むしろ私がお聞きしたいですわ。","ENG":"No. I'm the one with all the questions.","TWN":"不，我才想問您。"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"저 아이들이 위저드를 무너뜨린 배은망덕한 것들이란 사실을 알고 계셨나요?","JPN":"あの子たちがウィザードをめちゃくちゃにした恩知らずだということをご存じですか？","ENG":"Did you know that those brats are the ones who tore down Wizard?","TWN":"您知道那些人是毀掉巫師的叛徒嗎？"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"그래서 다른 아이들이 위저드의 도움을 받지 못하게 되었다는 것도?","JPN":"そのせいで他の子たちがウィザードの支援を受けられなくなったということは？","ENG":"And that's why the other children there can't receive any help?","TWN":"您也知道，有許多孩子因此而無法受到巫師的幫助嗎？"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};